INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-acfc4025-moex-00831', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '近年來雙薪家庭比例上升，由於父母忙於工作，因此托兒所、安親班等機構成為安置孩童的重要處所。 根據統計，臺灣目前有政府立案的各種安親班、補習班、才藝班數量遠遠超過全臺超商數量。此現象說 明隨著社會變遷，家庭的何種功能正在轉變？', '["生育功能", "經濟功能", "社會化功能", "傳遞社會地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00832', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '所謂「友善職場」，就是無歧視、重平等的職場。在職場中，勞工與雇主彼此尊重、合作，共同打造一 個性別平權的工作環境。下列何種作法，最有助於促進「友善職場」？', '["開放同志勞工因伴侶生病時可請家庭照顧假", "營造玻璃天花板環境以便落實性別實質平等", "健全性別職業隔離制度以保障女性就業機會", "降低女性勞動參與率以避免蠟燭兩頭燒現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00833', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '有關法律分類的敘述，下列何者正確？', '["民法：不成文法、私法、普通法、實體法", "民事訴訟法：成文法、私法、特別法、程序法", "刑事訴訟法：成文法、公法、普通法、程序法", "勞動基準法：不成文法、社會法、特別法、實體法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00834', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '隨著高齡化社會的來臨，國際移工的身影已深入臺灣家庭，然而媒體總以「口音怪異、膚色黝黑、吵雜 或是忠誠度不足、常常逃跑」來形容移工的樣貌。由此可知，媒體主要是透過下列何種方式來影響閱聽 人的認知？', '["總白癡化", "置入性行銷", "暴力行為的複製", "形塑刻板印象與歧視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00835', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '根據公民投票法之規定：「當國家遭受外力威脅，致國家主權有改變之虞，甲得經行政院院會之決議， 就攸關國家安全事項，交付公民投票。」關於甲的法定職權，下列敘述何者正確？', '["可向立法院提出覆議", "享有被動解散國會權", "可以提出憲法修正案", "掌理公務員懲戒事宜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00836', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '甲香雞排店位於社區中，炸雞排時排放的油煙與味道往往導致附近居民抗議，因此環保局對甲香雞排店 開罰並要求加裝符合環保標準的靜電油煙處理設備。若以香雞排價格為縱軸，香雞排數量為橫軸，針對 上述的分析說明，下列何者正確？', '["環保局對雞排店的開罰是屬於確立財產權的作法", "處罰與要求加裝過濾設備會導致市場供給線左移", "環保局可以對居民補貼來減少店家產生外部成本", "雞排店被勒令加裝環保設備即是體現了市場機能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00837', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '我國現行的立法委員選舉，其選舉制度如下：區域立委選舉採（甲）選舉制度，原住民立委選舉採（乙） 選舉制度，全國不分區立委選舉採（丙）選舉制度，下列敘述何者正確？', '["（甲）（乙）選舉制度皆有利於大黨", "（丙）以區域候選人所得票數比例換算政黨席位", "（乙）（丙）皆有婦女保障名額的限制", "（甲）為一個選區只有一人當選的選制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00838', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '若我國總統選舉在某次的票數統計，1號候選人得票率30.6%，2號候選人得票率38.5%，3號候選人得票 率0.7%，4號候選人得票率30.2%，依政治學理及相關法律來看，下列何者是2號候選人在選舉結束後， 最可能面臨的挑戰？', '["得票數未過半，無法當選，須於第二輪投票繼續努力", "得票數未過半，其他候選人可能會提出選舉無效之訴", "得票數未過半，其他候選人可能會提出當選無效之訴", "得票數未過半，可能讓國民認為有代表性不足的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00839', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '小楊時薪400元，為了省錢每餐固定支出60元，某日小楊花了1,500元搭乘高鐵參加兒子的大學畢業典 禮，請同事小許代班 6 小時，事後小楊請小許吃一客 350 元的豪華晚餐作為答謝，自己則點了一客 250 元的精緻晚餐。依上所述判斷，小楊這次參加兒子大學畢業典禮的機會成本是多少？', '["3,900元", "4,250元", "4,440元", "4,560元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00840', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '民國 103 年啟動的「十二年國教」政策，人數最多的基北區高中職免試入學，過去採用「會考總積點」 制度產生爭議；104年承辦免試入學的新北市政府教育局提出「7級總積分」新方案的構想；認為如果104年 放榜未產生爭議，則沿用「會考總積點」的舊方案，若有疑慮，則考慮採用「7級總積分」的新方案。關 於新北市政府教育局的作法，是否符合公共政策決定過程，下列敘述何者正確？', '["符合，因為行政機關提出新方案就已屬於政策合法化的過程", "符合，行政機關可以評估政策的效果來作為修正的判斷依據", "不符合，因為政策評估必須在公共政策規劃之前就必須實施", "不符合，因為若不繼續沿用舊方案，將會違反信賴保護原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:28+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
